            /** @description `'audit' | 'scan' | 'health' | 'reading'`. */
            kind: string;
            /** @description Kind-specific structured fields (action, severity, library_id, ...). */
            payload: unknown;
            /** @description Stable identifier within the kind. For aggregates, the bucket time. */
            source_id: string;
            summary: string;
